import { z } from 'zod';
import type {
  ClassificationResult,
  ClassificationSession,
  EmailMessage,
  HardAssertionResult,
  RulePattern,
} from '../types';
import { extractDomainFromEmail, findMatchingDomain, normalizeEmail } from '../utils/email-utils';
import { ensureCategoryScoreInitialized } from '../utils/initialization';
import { matchRulePattern } from '../utils/rule-matcher';
import { RulePatternSchema } from '../config/category-config-schema';

/**
 * Hard Assertions Stage
 *
 * Implements CONFIDENCE_FLOOR logic per SCORING_LOGIC.md "Hard Assertions" section.
 * Single match can directly elevate a top-level category to high confidence baseline.
 *
 * CANONICAL SIGNATURE: (email, session, result, config) => void
 *
 * Logic:
 * - If any hard assertion matches: categoryScore = max(categoryScore, CONFIDENCE_FLOOR)
 * - Mark flag: hardAssertion = true
 * - Where CONFIDENCE_FLOOR = settings.hardAssertions.confidenceFloor (absolute score, typically 1.0)
 * - This is an ABSOLUTE SCORE on the 0-aggregationCap scale, NOT normalized 0-1
 * - Mutates result.explainabilityTrace and result.scoreBreakdown instead of returning
 */

export interface HardAssertionConfig {
  fromDomainsRef?: {
    sourceGroup: string;
    confidence: 'high' | 'medium' | 'low';
  };
  subjectPrefixes?: string[];
  fromAddresses?: string[];
  customRules?: RulePattern[];
}

export interface HardAssertionStageConfig {
  hardAssertionsSettings: {
    confidenceFloor: number;
  };
  categorySignals: Record<string, { hardAssertions?: HardAssertionConfig }>;
  domainLookup: Record<
    string,
    {
      highConfidence: Array<{ domain: string; type?: string }>;
      mediumConfidence: Array<{ domain: string; type?: string }>;
      lowConfidence: Array<{ domain: string; type?: string }>;
    }
  >;
}

/**
 * Executes hard assertions stage of email classification
 *
 * CANONICAL SIGNATURE: Mutates result object instead of returning values
 *
 * @param email The email message to classify
 * @param session Classification session (batch-level metadata)
 * @param result Classification result to update (mutated in place)
 * @param config Configuration containing category signals and thresholds
 */
export function executeHardAssertions(
  email: EmailMessage,
  session: ClassificationSession,
  result: ClassificationResult,
  config: HardAssertionStageConfig
): void {
  const startTime = Date.now();

  const categoriesWithHardAssertions: string[] = [];
  const assertionResults: HardAssertionResult[] = [];

  const CONFIDENCE_FLOOR = config.hardAssertionsSettings.confidenceFloor;

  // Process each category that has hard assertions configured
  for (const [categoryName, categoryConfig] of Object.entries(config.categorySignals)) {
    if (!categoryConfig.hardAssertions) {
      continue;
    }

    const hardAssertions = categoryConfig.hardAssertions;
    let categoryHadAssertion = false;

    // Check fromDomainsRef (domain-based hard assertions)
    if (hardAssertions.fromDomainsRef) {
      const { sourceGroup, confidence } = hardAssertions.fromDomainsRef;

      // Only treat as hard assertion if confidence is 'high'
      if (confidence === 'high') {
        const domainGroup = config.domainLookup[sourceGroup];
        if (domainGroup) {
          const emailDomain = extractDomainFromEmail(email.from.email);
          const matchedDomain = findMatchingDomain(emailDomain, domainGroup, 'high');

          if (matchedDomain) {
            assertionResults.push({
              category: categoryName,
              triggered: true,
              assertionType: 'fromDomain',
              matchedValue: matchedDomain.domain,
              confidence: 'HIGH_CONFIDENCE',
              sourceGroup: sourceGroup,
              reason: `Email from domain '${emailDomain}' matches high-confidence domain '${matchedDomain.domain}' in group '${sourceGroup}'`,
            });
            categoryHadAssertion = true;
          }
        }
      }
    }

    // Check subjectPrefixes
    if (hardAssertions.subjectPrefixes) {
      const subject = email.subject.toLowerCase();

      for (const prefix of hardAssertions.subjectPrefixes) {
        if (subject.startsWith(prefix.toLowerCase())) {
          assertionResults.push({
            category: categoryName,
            triggered: true,
            assertionType: 'subjectPrefix',
            matchedValue: prefix,
            confidence: 'HIGH_CONFIDENCE',
            reason: `Subject '${email.subject}' starts with hard assertion prefix '${prefix}'`,
          });
          categoryHadAssertion = true;
          break; // First match is sufficient
        }
      }
    }

    // Check fromAddresses (exact email address matches)
    if (hardAssertions.fromAddresses) {
      const fromEmail = normalizeEmail(email.from.email);

      for (const address of hardAssertions.fromAddresses) {
        if (fromEmail === normalizeEmail(address)) {
          assertionResults.push({
            category: categoryName,
            triggered: true,
            assertionType: 'fromAddress',
            matchedValue: address,
            confidence: 'HIGH_CONFIDENCE',
            reason: `Email from address '${fromEmail}' matches hard assertion address '${address}'`,
          });
          categoryHadAssertion = true;
          break; // First match is sufficient
        }
      }
    }

    if (hardAssertions.customRules) {
      for (const rule of hardAssertions.customRules) {
        const match = matchRulePattern(email, rule);
        if (match.matched) {
          assertionResults.push({
            category: categoryName,
            triggered: true,
            assertionType: 'customRule',
            matchedValue: match.matchedValue,
            confidence: 'HIGH_CONFIDENCE',
            reason: `Custom hard assertion (${rule.operation}) matched '${match.matchedValue}' on field '${rule.field}'`,
          });
          categoryHadAssertion = true;
          break;
        }
      }
    }

    // Apply hard assertion score if any assertion matched
    if (categoryHadAssertion) {
      const currentScore = result.scoreBreakdown.categoryScores[categoryName]?.finalScore || 0;
      const newScore = Math.max(currentScore, CONFIDENCE_FLOOR);

      // Ensure category score is initialized using canonical helper
      ensureCategoryScoreInitialized(result, categoryName);

      result.scoreBreakdown.categoryScores[categoryName].hardAssertionBonus = CONFIDENCE_FLOOR;
      result.scoreBreakdown.categoryScores[categoryName].finalScore = newScore;
      categoriesWithHardAssertions.push(categoryName);
    }
  }

  // Update result.explainabilityTrace with hard assertions (mutate in place)
  result.explainabilityTrace.hardAssertions = assertionResults;

  // Track stage timing in session performance metrics
  const durationMs = Date.now() - startTime;
  if (!session.performanceMetrics.parallelStagesCount) {
    session.performanceMetrics.parallelStagesCount = 0;
  }

  // Store timing in explainability trace
  result.explainabilityTrace.stageTimings['hardAssertions'] = durationMs;
  result.explainabilityTrace.configurationRefs['hardAssertions'] = 'categorySignals.*.hardAssertions';

  // Update processing duration
  result.processingDurationMs += durationMs;
}

